// Plugin Registration System
class PluginRegistry {
    private static plugins: Map<string, PluginInterface> = new Map();

    public static register(plugin: PluginInterface): void {
        // Validate dependencies
        this.validateDependencies(plugin.getDependencies());

        // Register plugin
        this.plugins.set(plugin.getId(), plugin);

        // Initialize plugin
        plugin.initialize();
    }

    private static validateDependencies(deps: string[]): void {
        deps.forEach(dep => {
            if (!this.plugins.has(dep)) {
                throw new Error(`Dependency ${dep} not found`);
            }
        });
    }
}
